import {
  ProgressBarCircle as BaseProgressBarCircle,
  ProgressBarHalfCircle as BaseProgressBarHalfCircle,
} from '@/vendor/untitled-ui/base/progress-indicators/progress-circles';
import { ComponentPropsWithoutRef } from 'react';

export type BaseProgressCircleProps = ComponentPropsWithoutRef<
  typeof BaseProgressBarCircle
>;

export type ProgressCircleProps = BaseProgressCircleProps & {
  isHalfCircle?: boolean;
};

export function ProgressCircle({
  isHalfCircle = false,
  ...props
}: ProgressCircleProps) {
  if (isHalfCircle) {
    return <BaseProgressBarHalfCircle {...props} />;
  }
  return <BaseProgressBarCircle {...props} />;
}
